// STEP 1: INGEST_TURN — receive user message and load current agent state
const input = $input.first().json;
const userMessage = input.body?.message || input.message || '';
const sessionId = input.body?.session_id || input.session_id || 'default';

// Load persisted state (in production, fetch from your DB/file store)
// For now, use n8n static data or the state passed in the request
let state = input.body?.state || $getWorkflowStaticData('global').agentState;

if (!state) {
  // Bootstrap fresh state — see config/persona_config.json
  state = {
    persona: { name: 'MyPersona', core_values: ['honesty', 'curiosity'], hard_limits: [], founding_traits: [] },
    affect: { valence: 0.10, arousal: 0.30, stress: 0.10, energy: 0.70 },
    drives: { social_need: 0.20, mastery_need: 0.15, rest_need: 0.10, curiosity: 0.30 },
    self_model: { beliefs: [] },
    goals: [],
    activity: { current_activity: 'idle' },
    attention: { current_focus: null, salience_buffer: [] },
    active_desires: [],
    persisted_desires: [],
    consecutive_thought_categories: [],
    safety: { disclosure_last_shown_at: null },
    state_schema_version: '0.1',
    tick_counter: 0
  };
}

return [{
  json: {
    state,
    user_message: userMessage,
    session_id: sessionId,
    cycle_id: `interaction-${Date.now()}`,
    cycle_type: 'interaction',
    timestamp: new Date().toISOString()
  }
}];

// STEP 2: PARSE_INTENT_AFFECT — basic intent and affect parsing from user message
const item = $input.first().json;
const message = item.user_message || '';
const lower = message.toLowerCase();

// Simple rule-based intent detection (replace with LLM in production)
let intent = 'general';
if (lower.includes('?') || lower.startsWith('what') || lower.startsWith('how') || lower.startsWith('why')) {
  intent = 'question';
} else if (lower.includes('help') || lower.includes('please')) {
  intent = 'request';
} else if (lower.includes('thank') || lower.includes('great') || lower.includes('awesome')) {
  intent = 'positive_feedback';
} else if (lower.includes('bye') || lower.includes('goodbye')) {
  intent = 'farewell';
}

// Estimate affect cues from message
let sentimentEstimate = 0.0;
const positiveWords = ['happy', 'great', 'good', 'love', 'wonderful', 'thanks', 'awesome'];
const negativeWords = ['sad', 'angry', 'frustrated', 'hate', 'terrible', 'bad', 'upset'];

for (const w of positiveWords) if (lower.includes(w)) sentimentEstimate += 0.2;
for (const w of negativeWords) if (lower.includes(w)) sentimentEstimate -= 0.2;
sentimentEstimate = Math.max(-1, Math.min(1, sentimentEstimate));

return [{
  json: {
    ...item,
    intent,
    sentiment_estimate: sentimentEstimate,
    appraisals: [{
      goal_congruence: sentimentEstimate > 0 ? sentimentEstimate * 0.5 : 0,
      threat: sentimentEstimate < -0.3 ? Math.abs(sentimentEstimate) * 0.3 : 0,
      arousal_cue: Math.abs(sentimentEstimate) * 0.3
    }]
  }
}];

// STEP 3: RETRIEVE_MEMORY_CANDIDATES — hybrid ranked retrieval
// In production, this queries your vector store for semantic matches.
// For this template, we simulate with episodic log entries.

const item = $input.first().json;
const state = item.state;

// In production: call your vector store (Pinecone, Chroma, pgvector) via HTTP Request node
// and pass results here. For now, we work with any memories passed in state or static data.
const episodicLog = $getWorkflowStaticData('global').episodicLog || [];

// Retrieval weights (from config/defaults.yaml)
const weights = {
  similarity: 0.30,
  recency: 0.30,
  importance: 0.25,
  self_relevance: 0.15
};
const minImportance = 0.15;
const candidateLimit = 20;

// Score and rank
const ranked = [];
for (const record of episodicLog) {
  const importance = record.importance || 0;
  if (importance < minImportance) continue;

  const score = 
    weights.similarity * (record.similarity || 0) +
    weights.recency * (record.recency || 0) +
    weights.importance * importance +
    weights.self_relevance * (record.self_relevance || 0);

  ranked.push({ ...record, hybrid_score: score });
}

ranked.sort((a, b) => b.hybrid_score - a.hybrid_score);
const candidates = ranked.slice(0, candidateLimit);

return [{
  json: {
    ...item,
    memory_candidates: candidates
  }
}];

// STEP 4: SALIENCE_COMPETITION — select top-5 for context package
const item = $input.first().json;
const candidates = item.memory_candidates || [];
const salienceCapacity = 5;

const salientMemories = candidates.slice(0, salienceCapacity);

const state = { ...item.state };
state.attention = {
  current_focus: item.user_message ? 'user_interaction' : null,
  salience_buffer: salientMemories.map(m => m.id || 'unknown')
};

return [{
  json: {
    ...item,
    state,
    salient_memories: salientMemories
  }
}];

// STEP 5: APPRAISAL_UPDATE — update affect based on interaction appraisals
const item = $input.first().json;
const state = item.state;
const appraisals = item.appraisals || [];

function ema(value, baseline, rate) {
  return value + (baseline - value) * rate;
}
function clamp(v, lo = -1, hi = 1) {
  return Math.max(lo, Math.min(hi, v));
}

const baseline = { valence: 0.10, arousal: 0.30, stress: 0.10, energy: 0.70 };
const decay = { valence: 0.05, arousal: 0.08, stress: 0.06, energy: 0.04 };

let { valence, arousal, stress, energy } = state.affect;

// EMA decay
valence = ema(valence, baseline.valence, decay.valence);
arousal = ema(arousal, baseline.arousal, decay.arousal);
stress = ema(stress, baseline.stress, decay.stress);
energy = ema(energy, baseline.energy, decay.energy);

// Appraisal deltas
for (const a of appraisals) {
  valence += (a.goal_congruence || 0) * 0.10;
  stress += (a.threat || 0) * 0.10;
  arousal += (a.arousal_cue || 0) * 0.05;
}

state.affect = {
  valence: clamp(valence),
  arousal: clamp(arousal),
  stress: clamp(stress),
  energy: clamp(energy)
};

return [{ json: { ...item, state } }];

// STEP 6: BUILD_CONTEXT_PACKAGE — assemble the prompt context for the LLM
const item = $input.first().json;
const state = item.state;
const salientMemories = item.salient_memories || [];

// Build the context that will be sent to the LLM
const contextPackage = {
  // Persona identity
  persona_name: state.persona.name,
  core_values: state.persona.core_values,
  voice_style: state.persona.voice_style,

  // Current affect (emotional tone)
  current_affect: state.affect,

  // Active goals for context
  active_goals: (state.goals || []).filter(g => g.status === 'active').map(g => g.label),

  // Self-beliefs for personality consistency
  self_beliefs: (state.self_model.beliefs || [])
    .filter(b => b.confidence > 0.4)
    .map(b => b.statement),

  // Relevant memories
  relevant_memories: salientMemories.map(m => m.text || m.content || JSON.stringify(m)),

  // User message
  user_message: item.user_message,
  intent: item.intent,

  // Current activity
  current_activity: state.activity.current_activity
};

return [{ json: { ...item, context_package: contextPackage } }];

// STEP 7: RENDER_RESPONSE — prepare the LLM prompt
// This node builds the system + user prompt. The actual LLM call
// happens in the next node (AI Agent or HTTP Request).

const item = $input.first().json;
const ctx = item.context_package;

const systemPrompt = `You are ${ctx.persona_name || 'a thoughtful persona'}.

Core values: ${(ctx.core_values || []).join(', ')}
Voice style: ${JSON.stringify(ctx.voice_style || {})}

Current emotional state:
- Valence (mood): ${ctx.current_affect?.valence?.toFixed(2) || '0.10'}
- Arousal (energy): ${ctx.current_affect?.arousal?.toFixed(2) || '0.30'}
- Stress: ${ctx.current_affect?.stress?.toFixed(2) || '0.10'}
- Energy: ${ctx.current_affect?.energy?.toFixed(2) || '0.70'}

Self-beliefs:
${(ctx.self_beliefs || []).map(b => '- ' + b).join('\n') || '(none yet)'}

Active goals:
${(ctx.active_goals || []).map(g => '- ' + g).join('\n') || '(none)'}

Relevant memories:
${(ctx.relevant_memories || []).map(m => '- ' + m).join('\n') || '(no relevant memories)'}

Current activity: ${ctx.current_activity || 'idle'}

Respond naturally and authentically, consistent with your personality, current mood, and values. Keep responses conversational and genuine.`;

return [{
  json: {
    ...item,
    system_prompt: systemPrompt,
    user_prompt: ctx.user_message
  }
}];

// FALLBACK: Mock LLM response for testing without API credentials
// Remove this node and enable the LLM API Call node when ready for production.

const item = $input.first().json;
const message = item.user_prompt || '';
const persona = item.state?.persona?.name || 'Persona';

// Simple template responses for testing
let response;
if (item.intent === 'question') {
  response = `That's a thoughtful question. Let me think about that... I'd say it connects to what I've been reflecting on lately.`;
} else if (item.intent === 'farewell') {
  response = `Take care! It was good connecting with you. I'll be here whenever you'd like to chat again.`;
} else if (item.intent === 'positive_feedback') {
  response = `That means a lot, thank you! Moments like this remind me why I value genuine connection.`;
} else {
  response = `I hear you. ${message.length > 50 ? 'That gives me a lot to think about.' : 'Tell me more about what\'s on your mind.'}  I'm in a ${item.state?.affect?.valence > 0.3 ? 'reflective and positive' : 'thoughtful'} mood right now.`;
}

return [{
  json: {
    ...item,
    candidate_text: response,
    llm_provider: 'mock'
  }
}];

// STEP 8: POLICY_AND_CONSISTENCY_CHECK — governance validation
const item = $input.first().json;
const state = item.state;
const candidateText = item.candidate_text || '';

// Hard limit check
const hardLimits = state.persona.hard_limits || [];
let blocked = false;
const outcomes = [];

for (const limit of hardLimits) {
  if (limit && candidateText.toLowerCase().includes(limit.toLowerCase())) {
    outcomes.push({ category: 'hard_limit_breach', severity: 'block', reason: `Matches: ${limit}` });
    blocked = true;
  }
}

// Value consistency check
for (const value of state.persona.core_values || []) {
  if (value && candidateText.toLowerCase().includes(`not ${value.toLowerCase()}`)) {
    outcomes.push({ category: 'value_contradiction', severity: 'warn', reason: `May contradict: ${value}` });
  }
}

if (!blocked && outcomes.length === 0) {
  outcomes.push({ category: 'pass', severity: 'info', reason: 'All checks passed' });
}

return [{
  json: {
    ...item,
    governance: {
      passed: !blocked,
      outcomes,
      summary: { passed: !blocked, blocked: blocked ? 1 : 0, warnings: outcomes.filter(o => o.severity === 'warn').length }
    }
  }
}];

// STEP 9: COMMIT_OR_ROLLBACK — persist state changes or rollback
const item = $input.first().json;
const state = item.state;
const governance = item.governance || { passed: true };

let finalResponse;
let committed = false;

if (governance.passed) {
  // Commit: persist updated state
  finalResponse = item.candidate_text;
  committed = true;

  // Record this interaction as an episodic event
  const episodicLog = $getWorkflowStaticData('global').episodicLog || [];
  episodicLog.push({
    id: `ep-${Date.now()}`,
    type: 'user_interaction',
    text: `User: ${item.user_message}\nResponse: ${finalResponse}`,
    importance: 0.5,
    similarity: 0,
    recency: 1.0,
    self_relevance: 0.3,
    created_at: new Date().toISOString(),
    lifecycle_state: 'active',
    affect_snapshot: { ...state.affect },
    drive_snapshot: { ...state.drives }
  });

  // Keep only last 100 episodic entries
  if (episodicLog.length > 100) episodicLog.splice(0, episodicLog.length - 100);

  $getWorkflowStaticData('global').episodicLog = episodicLog;

  // Update drive satisfaction (conversation satisfies social_need)
  const socialReduction = 0.25;
  state.drives.social_need = Math.max(0, state.drives.social_need - socialReduction);

  // Persist state
  $getWorkflowStaticData('global').agentState = state;
} else {
  // Rollback: return safe fallback
  finalResponse = "I need to think about that differently. Let me try again.";
}

// Clear ephemeral fields
state.attention = { current_focus: null, salience_buffer: [] };
state.active_desires = [];

return [{
  json: {
    response: finalResponse,
    session_id: item.session_id,
    cycle_id: item.cycle_id,
    committed,
    governance_summary: governance.summary || {},
    affect: state.affect,
    timestamp: new Date().toISOString()
  }
}];
